  ('catalog-atomic-habits', 'atomic-habits', 'Atomic Habits', 'A practical playbook for building good habits and breaking bad ones with small repeated actions. Atomic Habits by James Clear focuses on habits, self improvement, and productivity within our bestsellers and reader favorites catalogue.', 'self-help', 'https://covers.openlibrary.org/b/isbn/9781847941831-L.jpg', null, 'Penguin Random House India', '2018', '9781847941831', '1847941834', 'English', 'Paperback', 320, 'curated'),
  ('catalog-deep-work', 'deep-work', 'Deep Work', 'A guide to focused work and attention management in a distracted world. Deep Work by Cal Newport focuses on focus, work, and attention within our career growth and reader favorites catalogue.', 'productivity', 'https://covers.openlibrary.org/b/isbn/9781455586691-L.jpg', null, 'Grand Central Publishing', '2016', '9781455586691', '1455586692', 'English', 'Paperback', 304, 'curated'),
  ('catalog-psychology-of-money', 'psychology-of-money', 'The Psychology of Money', 'Short essays on behavior, wealth, patience, and the psychology behind financial decisions. The Psychology of Money by Morgan Housel focuses on money, finance, and behavior within our bestsellers and reader favorites catalogue.', 'personal-finance', 'https://covers.openlibrary.org/b/isbn/9780857197689-L.jpg', null, 'Harriman House', '2020', '9780857197689', '0857197681', 'English', 'Paperback', 256, 'curated'),
  ('catalog-thinking-fast-and-slow', 'thinking-fast-and-slow', 'Thinking, Fast and Slow', 'A landmark book on decision-making, bias, and the two systems of thought. Thinking, Fast and Slow by Daniel Kahneman focuses on decision making, bias, and psychology within our career growth catalogue.', 'psychology', 'https://covers.openlibrary.org/b/isbn/9780141033570-L.jpg', null, 'Penguin Books', '2012', '9780141033570', '0141033576', 'English', 'Paperback', 512, 'curated'),
  ('catalog-power-of-habit', 'power-of-habit', 'The Power of Habit', 'How habits work in daily life, organizations, and social systems. The Power of Habit by Charles Duhigg focuses on habits, behavior, and change within our reader favorites catalogue.', 'self-help', 'https://covers.openlibrary.org/b/isbn/9780812981605-L.jpg', null, 'Random House Trade Paperbacks', '2014', '9780812981605', '081298160X', 'English', 'Paperback', 400, 'curated'),
  ('catalog-subtle-art', 'subtle-art', 'The Subtle Art of Not Giving a F*ck', 'A direct, modern self-help book on choosing what actually matters. The Subtle Art of Not Giving a F*ck by Mark Manson focuses on mindset, life advice, and self help within our bestsellers and reader favorites catalogue.', 'self-help', 'https://covers.openlibrary.org/b/isbn/9780062457714-L.jpg', '/covers/books/subtle-art', 'HarperOne', '2017', '9780062457714', '0062457713', 'English', 'Paperback', 224, 'curated'),
