  ('catalog-rich-dad-poor-dad', 'rich-dad-poor-dad', 'Rich Dad Poor Dad', 'A long-running personal finance title on assets, income, and financial mindset. Rich Dad Poor Dad by Robert T. Kiyosaki focuses on money, wealth, and personal finance within our career growth catalogue.', 'personal-finance', 'https://covers.openlibrary.org/b/isbn/9781612681139-L.jpg', null, 'Plata Publishing', '2017', '9781612681139', '1612681131', 'English', 'Paperback', 336, 'curated'),
