  ('catalog-one-hundred-years-of-solitude', 'one-hundred-years-of-solitude', 'One Hundred Years of Solitude', 'A landmark of world literature blending family saga, myth, and magical realism. One Hundred Years of Solitude by Gabriel Garcia Marquez sits within classic, nobel, and magical realism and the wider world classics and nobel prize winners shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9780241968581-L.jpg', null, 'Penguin Classics', '1967', '9780241968581', '0241968585', 'English', 'Paperback', 432, 'curated'),
  ('catalog-midnights-children', 'midnights-children', 'Midnight''s Children', 'A Booker Prize-winning modern classic that reimagines India''s birth through one extraordinary life. Midnight''s Children by Salman Rushdie sits within booker, indian author, and literary fiction and the wider booker prize winners and indian authors shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9780099578512-L.jpg', '/covers/books/midnights-children', 'Vintage', '2013', '9780099578512', '0099578514', 'English', 'Paperback', 672, 'curated'),
  ('catalog-life-of-pi', 'life-of-pi', 'Life of Pi', 'An imaginative Booker Prize-winning novel of survival, storytelling, and wonder. Life of Pi by Yann Martel sits within booker, adventure, and fiction and the wider booker prize winners shelf.', 'fiction', 'https://covers.openlibrary.org/b/id/7537383-L.jpg', null, 'Canongate Books', '2001', '9781786891686', '1786891689', 'English', 'Paperback', 336, 'curated'),
  ('catalog-god-of-small-things', 'the-god-of-small-things', 'The God of Small Things', 'A Booker Prize-winning Indian novel rich with memory, politics, and family history. The God of Small Things by Arundhati Roy sits within booker, indian author, and literary fiction and the wider booker prize winners and indian authors shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9780006550686-L.jpg', '/covers/books/the-god-of-small-things', 'HarperCollins', '1998-10-14', '9780006550686', '0006550681', 'English', 'Paperback', 368, 'curated'),
  ('catalog-white-tiger', 'the-white-tiger', 'The White Tiger', 'A sharp Booker Prize-winning portrait of class, ambition, and modern India. The White Tiger by Aravind Adiga sits within booker, indian author, and contemporary fiction and the wider booker prize winners and indian authors shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9781416562603-L.jpg', '/covers/books/the-white-tiger', 'Free Press / Simon & Schuster', '2008-10-14', '9781416562603', '1416562605', 'English', 'Paperback', 304, 'curated'),
  ('catalog-shame', 'shame', 'Shame', 'A powerful contemporary novel by one of the most celebrated voices in world literature. Shame by J. M. Coetzee sits within booker, literary fiction, and award winner and the wider booker prize winners shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9780099289524-L.jpg', '/covers/books/shame', 'Vintage', '1999', '9780099289524', '0099289520', 'English', 'Paperback', 272, 'curated'),
  ('catalog-gitanjali', 'gitanjali', 'Gitanjali', 'The Nobel Prize-winning collection that remains central to Indian literary history. Gitanjali by Rabindranath Tagore sits within nobel, indian author, and poetry and the wider nobel prize winners and indian authors shelf.', 'fiction', 'https://covers.openlibrary.org/b/id/8246100-L.jpg', '/covers/books/gitanjali', 'Rupa Publications', '1910', '9788171676118', '8171676111', 'English', 'Paperback', 160, 'curated'),
  ('catalog-beloved', 'beloved', 'Beloved', 'A Nobel laureate''s masterpiece exploring memory, trauma, and freedom. Beloved by Toni Morrison sits within nobel, classic, and literary fiction and the wider nobel prize winners shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9781400033416-L.jpg', null, 'Vintage', '1987', '9781400033416', '1400033411', 'English', 'Paperback', 352, 'curated'),
  ('catalog-the-plague', 'the-plague', 'The Plague', 'A philosophical modern classic by a Nobel laureate, still urgently relevant. The Plague by Albert Camus sits within nobel, classic, and philosophical fiction and the wider world classics and nobel prize winners shelf.', 'fiction', 'https://covers.openlibrary.org/b/isbn/9780141185132-L.jpg', null, 'Penguin Modern Classics', '2001', '9780141185132', '0141185139', 'English', 'Paperback', 320, 'curated'),
  ('catalog-the-7-habits-of-highly-effective-people', 'the-7-habits-of-highly-effective-people', 'The 7 Habits of Highly Effective People', 'A self-help and personal-development pick in personal effectiveness, first published in 1989. Classic personal-development book; useful for evergreen self-help catalogue. The 7 Habits of Highly Effective People by Stephen R. Covey focuses on self help, personal development, and personal effectiveness within our Self Help catalogue.', 'self-help', null, null, null, '1989', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-the-power-of-now', 'the-power-of-now', 'The Power of Now', 'A self-help and personal-development pick in mindfulness & spirituality, first published in 1997. Major spiritual self-help title; edition details vary widely. The Power of Now by Eckhart Tolle focuses on self help, personal development, and mindfulness & spirituality within our Self Help catalogue.', 'self-help', null, null, null, '1997', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-the-four-agreements', 'the-four-agreements', 'The Four Agreements', 'A self-help and personal-development pick in mindset & spirituality, first published in 1997. Evergreen spiritual/personal freedom self-help title. The Four Agreements by Don Miguel Ruiz focuses on self help, personal development, and mindset & spirituality within our Self Help catalogue.', 'self-help', null, null, null, '1997', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-mans-search-for-meaning', 'mans-search-for-meaning', 'Man''s Search for Meaning', 'A self-help and personal-development pick in meaning & resilience, first published in 1946. Classic meaning/resilience book; often shelved with self-help and psychology. Man''s Search for Meaning by Viktor E. Frankl focuses on self help, personal development, and meaning & resilience within our Self Help catalogue.', 'self-help', null, null, null, '1946', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-mindset', 'mindset', 'Mindset', 'A self-help and personal-development pick in growth mindset, first published in 2006. Important psychology-backed self-improvement title. Mindset by Carol S. Dweck focuses on self help, personal development, and growth mindset within our Self Help catalogue.', 'self-help', null, null, null, '2006', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-essentialism', 'essentialism', 'Essentialism', 'A self-help and personal-development pick in focus & prioritization, first published in 2014. Popular minimalism/prioritization book for productivity readers. Essentialism by Greg McKeown focuses on self help, personal development, and focus & prioritization within our Self Help catalogue.', 'self-help', null, null, null, '2014', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-getting-things-done', 'getting-things-done', 'Getting Things Done', 'A self-help and personal-development pick in productivity system, first published in 2001. Classic productivity system; revised editions are common. Getting Things Done by David Allen focuses on self help, personal development, and productivity system within our Self Help catalogue.', 'self-help', null, null, null, '2001', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-eat-that-frog', 'eat-that-frog', 'Eat That Frog!', 'A self-help and personal-development pick in productivity & procrastination, first published in 2001. Short, popular productivity/procrastination title. Eat That Frog! by Brian Tracy focuses on self help, personal development, and productivity & procrastination within our Self Help catalogue.', 'self-help', null, null, null, '2001', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-make-time', 'make-time', 'Make Time', 'A self-help and personal-development pick in focus & time management, first published in 2018. Modern practical productivity title. Make Time by Jake Knapp and John Zeratsky focuses on self help, personal development, and focus & time management within our Self Help catalogue.', 'self-help', null, null, null, '2018', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-the-one-thing', 'the-one-thing', 'The ONE Thing', 'A self-help and personal-development pick in focus & success, first published in 2013. Popular focus/success productivity book. The ONE Thing by Gary Keller and Jay Papasan focuses on self help, personal development, and focus & success within our Self Help catalogue.', 'self-help', null, null, null, '2013', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-grit', 'grit', 'Grit', 'A self-help and personal-development pick in resilience & perseverance, first published in 2016. Psychology-backed success/resilience bestseller. Grit by Angela Duckworth focuses on self help, personal development, and resilience & perseverance within our Self Help catalogue.', 'self-help', null, null, null, '2016', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-drive', 'drive', 'Drive', 'A self-help and personal-development pick in motivation, first published in 2009. Popular motivation book used in business and personal-development categories. Drive by Daniel H. Pink focuses on self help, personal development, and motivation within our Self Help catalogue.', 'self-help', null, null, null, '2009', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-daring-greatly', 'daring-greatly', 'Daring Greatly', 'A self-help and personal-development pick in courage & vulnerability, first published in 2012. Major vulnerability/courage self-development title. Daring Greatly by Brené Brown focuses on self help, personal development, and courage & vulnerability within our Self Help catalogue.', 'self-help', null, null, null, '2012', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-the-gifts-of-imperfection', 'the-gifts-of-imperfection', 'The Gifts of Imperfection', 'A self-help and personal-development pick in self-acceptance, first published in 2010. Popular self-acceptance and shame-resilience title. The Gifts of Imperfection by Brené Brown focuses on self help, personal development, and self acceptance within our Self Help catalogue.', 'self-help', null, null, null, '2010', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-cant-hurt-me', 'cant-hurt-me', 'Can''t Hurt Me', 'A self-help and personal-development pick in discipline & resilience, first published in 2018. High-demand discipline/resilience memoir-self-help hybrid. Can''t Hurt Me by David Goggins focuses on self help, personal development, and discipline & resilience within our Self Help catalogue.', 'self-help', null, null, null, '2018', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
