  ('catalog-the-magic-of-thinking-big', 'the-magic-of-thinking-big', 'The Magic of Thinking Big', 'A self-help and personal-development pick in success mindset, first published in 1959. Classic confidence and success mindset book. The Magic of Thinking Big by David J. Schwartz focuses on self help, personal development, and success mindset within our Self Help catalogue.', 'self-help', null, null, null, '1959', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
  ('catalog-psycho-cybernetics', 'psycho-cybernetics', 'Psycho-Cybernetics', 'A self-help and personal-development pick in self-image & confidence, first published in 1960. Classic self-image and performance-improvement title. Psycho-Cybernetics by Maxwell Maltz focuses on self help, personal development, and self image & confidence within our Self Help catalogue.', 'self-help', null, null, null, '1960', null, null, 'English', 'Paperback / common retail edition', null, 'curated'),
